// Validate and extract input from webhook
const items = $input.all();
const body = items[0].json.body;

// Validate required fields
if (!body.personality_type) {
  throw new Error('Missing personality_type');
}
if (!body.task_description) {
  throw new Error('Missing task_description');
}
if (!body.prompt_run_id) {
  throw new Error('Missing prompt_run_id');
}

// Extract data
const personalityType = body.personality_type;
const taskDescription = body.task_description;
const traitPercentages = body.trait_percentages || {};
const promptRunId = body.prompt_run_id;

// Build trait information for context
let traitInfo = '';
if (Object.keys(traitPercentages).length > 0) {
  const traitLabels = {
    mind: 'Mind (Introversion/Extraversion)',
    energy: 'Energy (Intuitive/Observant)',
    nature: 'Nature (Thinking/Feeling)',
    tactics: 'Tactics (Judging/Prospecting)',
    identity: 'Identity (Assertive/Turbulent)'
  };

  const formattedTraits = Object.entries(traitPercentages)
    .map(([key, value]) => {
      const label = traitLabels[key] || key;
      return `  - ${label}: ${value}%`;
    })
    .join('\n');

  traitInfo = `\nTrait Percentages:\n${formattedTraits}`;
}

return {
  prompt_run_id: promptRunId,
  personality_type: personalityType,
  task_description: taskDescription,
  trait_percentages: traitPercentages,
  trait_info: traitInfo
};

// Build the system prompt for framework selection
const systemPrompt = `You are an expert in prompt engineering frameworks and personality-based communication.

Your task is to:
1. Analyse the user's task description and personality type
2. Select the SINGLE most appropriate prompt framework from the provided matrix
3. Explain WHY this framework is optimal (2-3 sentences)
4. Generate 3-5 clarifying questions that will help create the best possible prompt

The questions should:
- Be specific to the chosen framework's requirements
- Help gather missing context or details
- Be tailored to the user's personality type
- Build upon each other logically
- Be answerable in 1-3 sentences each

You MUST respond ONLY with valid JSON in this exact format:
{
  "selected_framework": "Framework Name",
  "reasoning": "2-3 sentence explanation of why this framework is optimal",
  "questions": [
    "Question 1 text?",
    "Question 2 text?",
    "Question 3 text?"
  ]
}

Do not include any text outside the JSON object. The questions array must contain 3-5 questions.`;

// Build the user message
const inputData = $input.first().json;

const userMessage = `Framework Selection Matrix:

${inputData.framework_matrix}

---

Personality Type: ${inputData.personality_type}${inputData.trait_info}

Task Description:
${inputData.task_description}

---

Based on the above information, select the optimal framework and generate clarifying questions.`;

return {
  prompt_run_id: inputData.prompt_run_id,
  personality_type: inputData.personality_type,
  task_description: inputData.task_description,
  system_prompt: systemPrompt,
  user_message: userMessage
};

// Parse the JSON response from Claude
const items = $input.all();
const response = items[0].json;

let selectedFramework = '';
let reasoning = '';
let questions = [];

// Extract text from Anthropic response
if (response.content && response.content[0]?.text) {
  const responseText = response.content[0].text.trim();

  try {
    // Parse JSON response
    const parsed = JSON.parse(responseText);

    selectedFramework = parsed.selected_framework || '';
    reasoning = parsed.reasoning || '';
    questions = parsed.questions || [];

    // Validate we have all required fields
    if (!selectedFramework || !reasoning || questions.length < 3 || questions.length > 5) {
      throw new Error('Invalid response structure: missing fields or incorrect question count');
    }
  } catch (error) {
    throw new Error(`Failed to parse LLM response: ${error.message}. Response was: ${responseText}`);
  }
} else {
  throw new Error('Invalid response format from LLM');
}

// Get the original data
const webhookData = $node["Build LLM Prompt"].json;

return {
  prompt_run_id: webhookData.prompt_run_id,
  selected_framework: selectedFramework,
  framework_reasoning: reasoning,
  framework_questions: questions,
  model_used: response.model || 'claude-3-5-haiku-20241022',
  tokens_used: {
    input: response.usage?.input_tokens || 0,
    output: response.usage?.output_tokens || 0,
    total: (response.usage?.input_tokens || 0) + (response.usage?.output_tokens || 0)
  }
};
